export enum ConflictStatus {
  ESCALATING = 'escalating',
  ACTIVE = 'active',
  DEESCALATING = 'deescalating',
  CEASEFIRE = 'ceasefire',
  HISTORICAL = 'historical'
}

export enum ConflictType {
  ARMED = 'armed',
  CYBER = 'cyber',
  TRADE = 'trade',
  TENSION = 'tension'
}

export interface Location {
  lat: number;
  lng: number;
  country: string;
  region: string;
}

export interface Perspective {
  summary: string[];
  sources: string[];
}

