}

import { GoogleGenAI, Type } from "@google/genai";
import { Conflict } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getConflictAnalysis = async (conflictName: string): Promise<any> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Provide a detailed multi-perspective analysis for the following conflict: ${conflictName}. 
      Include three viewpoints: Western Media, Regional Media, and Official Statements. 
      Format as JSON with keys: western, regional, official, each containing 'summary' (array of strings) and 'sources' (array of strings).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            western: {
              type: Type.OBJECT,
              properties: {
                summary: { type: Type.ARRAY, items: { type: Type.STRING } },
                sources: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ['summary', 'sources']
            },
            regional: {
              type: Type.OBJECT,
              properties: {
                summary: { type: Type.ARRAY, items: { type: Type.STRING } },
                sources: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ['summary', 'sources']
            },
            official: {
              type: Type.OBJECT,
              properties: {
                summary: { type: Type.ARRAY, items: { type: Type.STRING } },
                sources: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ['summary', 'sources']
            }
          },
          required: ['western', 'regional', 'official']
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return null;
  }
};

export const getGlobalSummary = async (conflicts: Conflict[]): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Summarize the current global conflict landscape in 3 concise sentences based on these events: ${conflicts.map(c => c.name).join(', ')}.`
    });
    return response.text || "Tracking global peace and stability through data.";
  } catch (error) {
    return "AI analysis currently unavailable. Tracking active global conflicts.";
  }
};

