import React from 'react';
import { Conflict } from '../types';
import { TYPE_COLORS } from '../constants';

interface TimelineProps {
  conflicts: Conflict[];
}

const Timeline: React.FC<TimelineProps> = ({ conflicts }) => {
  const startYear = 1945;
  const endYear = 2026;
  const totalYears = endYear - startYear;

  const getX = (dateStr: string) => {
    const year = parseInt(dateStr.split('-')[0]);
    return ((year - startYear) / totalYears) * 100;
  };

  const getWidth = (start: string, end: string | null) => {
    const startY = parseInt(start.split('-')[0]);
    const endY = end ? parseInt(end.split('-')[0]) : endYear;
    return ((endY - startY) / totalYears) * 100;
  };

  const sortedConflicts = [...conflicts].sort((a, b) => a.startDate.localeCompare(b.startDate));

  return (
    <div className="w-full h-full bg-white overflow-hidden flex flex-col">
      <div className="p-8 border-b">
        <h2 className="text-2xl font-bold text-zinc-800 mb-2">Historical Conflict Timeline</h2>
        <p className="text-zinc-500 text-sm">Mapping the evolution of global security from 1945 to present.</p>
      </div>

      <div className="flex-1 overflow-x-auto overflow-y-auto p-12 bg-zinc-50">
        <div className="relative min-w-[2000px] h-[600px] bg-white border border-zinc-200 rounded-2xl shadow-sm p-10">
          {/* Year Markers */}
          <div className="absolute top-0 left-0 w-full h-full pointer-events-none">
            {Array.from({ length: Math.ceil(totalYears / 10) + 1 }).map((_, i) => {
              const year = startYear + (i * 10);
              const left = (i * 10 / totalYears) * 100;
              return (
                <div key={year} className="absolute h-full border-l border-zinc-100" style={{ left: `${left}%` }}>
                  <span className="absolute bottom-[-24px] left-0 transform -translate-x-1/2 text-[10px] font-bold text-zinc-400">
                    {year}
                  </span>
                </div>
              );
            })}
          </div>

          {/* Conflict Bars */}
          <div className="space-y-4 pt-10">
            {sortedConflicts.map((conflict, idx) => (
              <div 
                key={conflict.id}
                className="group relative h-8 rounded-lg shadow-sm border border-white/20 transition-all hover:scale-[1.01] hover:shadow-md cursor-pointer"
                style={{
                  left: `${getX(conflict.startDate)}%`,
                  width: `${Math.max(2, getWidth(conflict.startDate, conflict.endDate))}%`,
                  backgroundColor: TYPE_COLORS[conflict.type].text,
                }}
              >
                <div className="absolute top-1/2 -translate-y-1/2 left-3 whitespace-nowrap text-white text-[11px] font-bold pointer-events-none overflow-hidden text-ellipsis max-w-full">
                  {conflict.name}
                </div>
                {/* Tooltip on hover */}
                <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 hidden group-hover:block bg-zinc-900 text-white text-xs px-3 py-1.5 rounded-lg z-50 whitespace-nowrap shadow-xl">
                  {conflict.name} ({conflict.startDate.split('-')[0]} - {conflict.endDate ? conflict.endDate.split('-')[0] : 'Present'})
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Timeline;

import React from 'react';
import { Conflict, ConflictStatus } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { STATUS_COLORS, TYPE_COLORS } from '../constants';

interface DashboardProps {
  conflicts: Conflict[];
}

const Dashboard: React.FC<DashboardProps> = ({ conflicts }) => {
  const statusStats = conflicts.reduce((acc, curr) => {
    acc[curr.status] = (acc[curr.status] || 0) + 1;
    return acc;
  }, {} as any);

  const typeStats = conflicts.reduce((acc, curr) => {
    acc[curr.type] = (acc[curr.type] || 0) + 1;
    return acc;
  }, {} as any);

  const statusData = Object.entries(statusStats).map(([name, value]) => ({ name, value }));
  const typeData = Object.entries(typeStats).map(([name, value]) => ({ name, value }));

  return (
    <div className="w-full min-h-full bg-zinc-50 p-8 space-y-8">
      <header className="mb-8">
        <h2 className="text-3xl font-bold text-zinc-900">Conflict Analytics</h2>
        <p className="text-zinc-500">Global trends and statistical breakdown of ongoing tensions.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border">
          <p className="text-xs font-bold text-zinc-400 uppercase tracking-widest mb-1">Active Conflicts</p>
          <p className="text-4xl font-bold text-zinc-900">{conflicts.filter(c => c.status === ConflictStatus.ACTIVE).length}</p>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-red-100">
          <p className="text-xs font-bold text-red-400 uppercase tracking-widest mb-1">Escalating</p>
          <p className="text-4xl font-bold text-red-600">{conflicts.filter(c => c.status === ConflictStatus.ESCALATING).length}</p>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border">
          <p className="text-xs font-bold text-zinc-400 uppercase tracking-widest mb-1">Regions Impacted</p>
          <p className="text-4xl font-bold text-zinc-900">{new Set(conflicts.map(c => c.location.region)).size}</p>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border">
          <p className="text-xs font-bold text-zinc-400 uppercase tracking-widest mb-1">Avg Intensity</p>
          <p className="text-4xl font-bold text-zinc-900">{(conflicts.reduce((acc, c) => acc + c.intensity, 0) / conflicts.length).toFixed(1)}</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-2xl shadow-sm border">
          <h3 className="text-lg font-bold text-zinc-800 mb-6">Status Distribution</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={statusData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" fontSize={12} tickLine={false} axisLine={false} />
                <YAxis fontSize={12} tickLine={false} axisLine={false} />
                <Tooltip 
