                />
                <Bar dataKey="value" radius={[4, 4, 0, 0]}>
                  {statusData.map((entry: any, index: number) => (
                    <Cell key={index} fill={STATUS_COLORS[entry.name as ConflictStatus].text} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-2xl shadow-sm border">
          <h3 className="text-lg font-bold text-zinc-800 mb-6">Conflict Types</h3>
          <div className="h-[300px]">
