              className="text-sm bg-white border rounded-lg px-3 py-1.5 focus:outline-none focus:ring-2 focus:ring-blue-500/20"
            >
              <option value="All">All Regions</option>
              {REGIONS.map(r => <option key={r} value={r}>{r}</option>)}
            </select>
            <select 
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
              className="text-sm bg-white border rounded-lg px-3 py-1.5 focus:outline-none focus:ring-2 focus:ring-blue-500/20"
            >
              <option value="All">All Status</option>
              {Object.values(ConflictStatus).map(s => <option key={s} value={s}>{s.charAt(0).toUpperCase() + s.slice(1)}</option>)}
            </select>
            <button className="p-2 hover:bg-zinc-100 rounded-lg text-zinc-400 hover:text-blue-600 transition-colors">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </button>
          </div>
        </header>

        {/* Dynamic View Content */}
        <div className="flex-1 relative">
          {viewMode === 'map' && (
            <MapView 
              conflicts={filteredConflicts as any} 
              onSelect={setSelectedConflict}
              selectedId={selectedConflict?.id}
            />
          )}
          {viewMode === 'timeline' && (
            <Timeline conflicts={filteredConflicts as any} />
          )}
          {viewMode === 'dashboard' && (
            <Dashboard conflicts={filteredConflicts as any} />
          )}
          {viewMode === 'news' && (
            <div className="h-full flex flex-col items-center justify-center bg-zinc-50 p-12 text-center">
              <div className="w-16 h-16 bg-blue-100 text-blue-600 rounded-2xl flex items-center justify-center mb-6">
                <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 20H5a2 2 0 01-2-2V6a2 2 0 012-2h10a2 2 0 012 2v1m2 13a2 2 0 01-2-2V7m2 13a2 2 0 002-2V9a2 2 0 00-2-2h-2m-4-3H9M7 16h6M7 8h6v4H7V8z" /></svg>
              </div>
              <h2 className="text-2xl font-bold text-zinc-900 mb-2">Live RSS Intelligence Feed</h2>
              <p className="text-zinc-500 max-w-md mx-auto">Connecting to global news sources... This feature is part of the Phase 4 development roadmap.</p>
              <button className="mt-8 px-6 py-2.5 bg-blue-600 hover:bg-blue-700 text-white font-semibold rounded-xl transition-all shadow-lg shadow-blue-500/20">
                Register for Alerts
              </button>
            </div>
          )}
        </div>

        {/* Global Footer (Subtle) */}
        <footer className="h-10 border-t bg-white px-8 flex items-center justify-between z-40 text-[10px] uppercase font-bold text-zinc-400 tracking-widest">
          <div>© 2026 Conflict Tracker Intelligence Network</div>
          <div className="flex space-x-4">
            <span className="hover:text-zinc-600 cursor-pointer">Methodology</span>
            <span className="hover:text-zinc-600 cursor-pointer">Data Policy</span>
            <span className="text-green-500">System Ready</span>
          </div>
        </footer>

        {/* Contextual Side Panels */}
        <Sidebar 
          conflict={selectedConflict} 
          onClose={() => setSelectedConflict(null)} 
        />
      </main>
    </div>
  );
};

interface NavIconProps {
  icon: string;
  label: string;
  active: boolean;
  onClick: () => void;
}

const NavIcon: React.FC<NavIconProps> = ({ icon, label, active, onClick }) => {
  const getIcon = () => {
    switch (icon) {
      case 'map': return <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 20l-5.447-2.724A1 1 0 013 16.382V5.618a1 1 0 011.447-.894L9 7m0 13l6-3m-6 3V7m6 10l4.553 2.276A1 1 0 0021 18.382V7.618a1 1 0 00-.553-.894L15 4m0 13V4m0 0L9 7" />;
      case 'timeline': return <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />;
      case 'stats': return <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />;
      case 'news': return <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 20H5a2 2 0 01-2-2V6a2 2 0 012-2h10a2 2 0 012 2v1m2 13a2 2 0 01-2-2V7m2 13a2 2 0 002-2V9a2 2 0 00-2-2h-2m-4-3H9M7 16h6M7 8h6v4H7V8z" />;
      default: return null;
    }
  };

  return (
    <button 
      onClick={onClick}
      className={`group relative p-3 rounded-xl transition-all duration-300 ${active ? 'bg-blue-600 text-white scale-110' : 'text-zinc-500 hover:text-zinc-300 hover:bg-zinc-800'}`}
    >
      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
        {getIcon()}
      </svg>
      {/* Tooltip */}
      <div className="absolute left-full ml-4 px-2 py-1 bg-zinc-800 text-white text-[10px] font-bold rounded opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap uppercase tracking-widest z-[100]">
        {label}
      </div>
    </button>
  );
};

export default App;
